import{_ as i,o as a,c as t,ae as n}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Push Notification Implementation","description":"","frontmatter":{"title":"Push Notification Implementation","slug":"push-notifications"},"headers":[],"relativePath":"developer-hub/push-notifications.md","filePath":"developer-hub/push-notifications.md"}'),o={name:"developer-hub/push-notifications.md"};function r(l,e,s,c,h,p){return a(),t("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Push notifications continue to be a reliable channel to re-engage your users back into your platform where they receive the best possible experience with your brand. Typical campaigns run through these channels are effective, but they can be difficult to properly track.</p><p>Branch can be used to help power your push notification campaigns through the use of Branch Links.</p><h3 id="push-notifications-use-cases" tabindex="-1">Push Notifications Use Cases <a class="header-anchor" href="#push-notifications-use-cases" aria-label="Permalink to &quot;Push Notifications Use Cases&quot;">​</a></h3><ul><li>Re-engage current users on new product launches, sales, etc.</li><li>Attribute downstream app events push notification</li></ul><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li>User receives a push notification</li><li>App opens</li><li>User is deep-linked into specific app content</li><li>Events (ex. purchases, sign-ups, etc.) are attributed back to push notification campaign</li></ol><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Branch Short Links are available to all customers of the Branch Growth Platform. However, access to Branch Deep Links and the Deep Linking API is part of our Engagement package. Learn more on our <a href="./packaging.html">pricing</a> page.</p><h2 id="integration-guide" tabindex="-1">Integration Guide <a class="header-anchor" href="#integration-guide" aria-label="Permalink to &quot;Integration Guide&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Developer Required</p><p>Developers knowledgeable with APIs, Web, and Mobile Development may be required.</p></div><h3 id="_1-create-configure-your-branch-link" tabindex="-1">1. Create &amp; Configure your Branch Link <a class="header-anchor" href="#_1-create-configure-your-branch-link" aria-label="Permalink to &quot;1. Create &amp; Configure your Branch Link&quot;">​</a></h3><p>Branch Link creation options:</p><ul><li><a href="./create-quick-links.html">Short Link</a></li><li><a href="./deep-linking-api.html">Deep Linking API</a></li><li><a href="./native-sdks-overview.html">Mobile SDKs</a></li><li><a href="./web-sdk-overview.html">Web SDK</a></li><li><a href="https://chrome.google.com/webstore/detail/branch-link-creator/pekdpppibljpmpbcjelehhnldnfbglgf" target="_blank" rel="noreferrer">Chrome Extension</a></li></ul><p>Additional information on configuring your Branch Link can be found <a href="./creating-a-deep-link.html">here</a>.</p><h3 id="_2-embed-the-branch-link-into-the-push-notification-payload" tabindex="-1">2. Embed the Branch Link into the push notification payload <a class="header-anchor" href="#_2-embed-the-branch-link-into-the-push-notification-payload" aria-label="Permalink to &quot;2. Embed the Branch Link into the push notification payload&quot;">​</a></h3><ul><li><a href="./ios-advanced-features.html#push-notifications">iOS Push</a></li><li><a href="./android-advanced-features.html#push-notifications">Android Push</a></li></ul><p>You may also insert your Branch Link in the push notification sending UI of your Push Notification Provider:</p><ul><li>Braze</li><li>Sailthru</li><li>Mixpanel</li><li>Responsys</li><li>Localytics</li><li>OneSignal</li></ul><p>Please see your Push Notification Provider&#39;s documentation for setting up and enabling deep linking through push notifications.</p><h3 id="_3-handle-push-notification-in-the-mobile-app" tabindex="-1">3. Handle Push Notification in the Mobile App <a class="header-anchor" href="#_3-handle-push-notification-in-the-mobile-app" aria-label="Permalink to &quot;3. Handle Push Notification in the Mobile App&quot;">​</a></h3><p><a href="./ios-basic-integration.html#6-initialize-branch">iOS</a></p><ul><li><p>Call <code>.handlePushNotification(userinfo)</code> in AppDelegate <code>UIApplication.didReceiveRemoteNotifcation()</code></p><ul><li>For iOS 10+ call <code>.handlePushNotification(response.notification.request.content.userInfo)</code> in App Delegate <code>UNUserNotificationCenter.didReceive()</code></li></ul></li></ul><p><a href="./android-basic-integration.html#6-initialize-branch">Android</a></p><ul><li>Call <code>.setIntent(intent)</code> &amp; <code>.reInitSession()</code> in <code>.onNewIntent()</code> of Activity handling deep link</li></ul>',25)])])}const f=i(o,[["render",r]]);export{d as __pageData,f as default};
